// ============ API : Génération de facture PROFORMA Échange (Port Taxes) ============
// Remplit le template "ECHANGE PORT TAXES". Les CHARGES écrites = uniquement les
// lignes cochées de la révision Échange (passées dans p.lines). Le reste du tableau
// de charges du template est vidé, et le total est recalculé.
// Le template est EMBARQUÉ en base64 (TPL_B64) -> aucun fichier externe requis.
const { isLicenseActive } = require('./license.js');

const TPL_B64 = "";
const SHEET = 'ECHANGE PORT TAXES';
const FIRST_CHARGE_ROW = 27;
const LAST_CHARGE_ROW = 52;      // zone de charges (le total I55 = SUM(I27:I52))
const STYLE_ROW = 29;            // ligne de charge de référence pour le style
function num(v){ var n = parseFloat(String(v == null ? '' : v).replace(/[^\d.\-]/g, '')); return isNaN(n) ? 0 : n; }

async function fillProforma(ExcelJS, p){
  const wb = new ExcelJS.Workbook();
  await wb.xlsx.load(Buffer.from(TPL_B64, 'base64'));
  const ws = wb.getWorksheet(SHEET) || wb.worksheets[0];

  // ---- En-tête ----
  ws.getCell('D5').value  = p.transitaire || '';            // Nom du transitaire (libellé BP)
  ws.getCell('F6').value  = p.bp || '';                     // Business Partner (code)
  ws.getCell('F7').value  = p.contractAcc || '';            // Contract Account
  ws.getCell('F8').value  = p.companyCode || 'CI12';        // Company code
  ws.getCell('C11').value = p.vessel || '';                 // Vessel name
  ws.getCell('C12').value = p.voyage || '';                 // Voyage number
  ws.getCell('C17').value = num(p.c40frigo);                // 40' Frigo
  ws.getCell('D17').value = num(p.c20sec);                  // 20' Sec
  ws.getCell('E17').value = num(p.c40sec);                  // 40' Sec
  ws.getCell('G19').value = (p.commodityCode == null ? '' : String(p.commodityCode)); // Code M/se
  if (p.commodityName) ws.getCell('C19').value = String(p.commodityName);  // nom réel (évite le décalage Data du template)
  ws.getCell('C20').value = p.deliveryZone || 'ABIDJAN';    // Zone
  if (p.footer) ws.getCell('B21').value = String(p.footer); // External billing footer
  ws.getCell('C24').value = p.ubli || '';                   // UBLI / réf
  if (p.type) ws.getCell('D24').value = p.type;             // ECHANGE / TRANSIT / TBL
  ws.getCell('E24').value = p.client || '';                 // Client
  if (p.facturier) ws.getCell('I21').value = p.facturier;   // Code facturier

  // ---- Charges = lignes cochées ----
  var lines = Array.isArray(p.lines) ? p.lines : [];
  // 1) vider toute la zone de charges (B..K) en gardant le style
  for (var r = FIRST_CHARGE_ROW; r <= LAST_CHARGE_ROW; r++){
    for (var col = 2; col <= 11; col++){ ws.getCell(r, col).value = null; }
  }
  // 2) écrire les lignes (max = capacité de la zone)
  var cap = LAST_CHARGE_ROW - FIRST_CHARGE_ROW + 1;
  var n = Math.min(lines.length, cap);
  var total = 0;
  for (var i = 0; i < n; i++){
    var l = lines[i] || {};
    var r = FIRST_CHARGE_ROW + i;
    var qty = num(l.qty), rate = num(l.rate), vat = (l.vat ? 1 : 0);
    var ht = qty * rate;
    var tva = vat ? Math.round(ht * 0.18) : 0;
    var ttc = ht + tva;
    total += ttc;
    // copier le style de la ligne de référence sur chaque cellule B..K
    for (var col = 2; col <= 11; col++){
      try { ws.getCell(r, col).style = ws.getCell(STYLE_ROW, col).style; } catch(e){}
    }
    ws.getCell(r, 2).value = l.desc || '';            // B Description
    ws.getCell(r, 3).value = l.unit || '';            // C Base/Unité
    ws.getCell(r, 4).value = qty;                     // D Qté
    ws.getCell(r, 5).value = rate;                    // E Taux
    ws.getCell(r, 6).value = ht;                      // F MontantHT
    ws.getCell(r, 7).value = vat;                     // G TVA
    ws.getCell(r, 8).value = tva;                     // H MontantTVA
    ws.getCell(r, 9).value = ttc;                     // I Montant TTC
    ws.getCell(r, 10).value = l.code || '';           // J Material Code
    ws.getCell(r, 11).value = l.desc || '';           // K libellé
  }
  // 3) total (viewer-proof)
  ws.getCell('I55').value = total;

  try { wb.calcProperties = wb.calcProperties || {}; wb.calcProperties.fullCalcOnLoad = true; } catch (e) {}
  return await wb.xlsx.writeBuffer();
}

function safeName(s){ return String(s || '').replace(/[^A-Za-z0-9_\-]/g, '_').slice(0, 40); }

module.exports = async (req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') { res.status(200).end(); return; }

  if (req.method === 'GET') {
    var diag = { ok: true, node: process.version, tpl: !!(TPL_B64 && TPL_B64.length), tplLen: TPL_B64 ? TPL_B64.length : 0, sheet: SHEET };
    try { require('exceljs'); diag.exceljs = true; } catch (e) { diag.exceljs = false; diag.exceljsErr = e.message; }
    res.status(200).json(diag); return;
  }
  if (req.method !== 'POST') { res.status(405).json({ ok: false, error: 'POST uniquement' }); return; }

  var active = false;
  try { active = await isLicenseActive(); } catch (e) { active = false; }
  if (!active) { res.status(403).json({ ok: false, blocked: true, error: 'Licence inactive' }); return; }

  try {
    const ExcelJS = require('exceljs');
    let body = req.body;
    if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) { body = {}; } }
    const p = (body && body.proforma) || body || {};
    const buf = await fillProforma(ExcelJS, p);
    const b64 = Buffer.from(buf).toString('base64');
    const fname = 'Proforma_' + (safeName(p.bl) || safeName(p.ubli) || safeName(p.client) || 'echange') + '.xlsx';
    res.status(200).json({ ok: true, b64: b64, filename: fname });
  } catch (e) {
    res.status(200).json({ ok: false, error: 'Erreur génération proforma : ' + e.message });
  }
};
